import{_ as a,c as i,o as t,ag as o}from"./chunks/framework.B-XtCDNB.js";const m=JSON.parse('{"title":"Compiler Guide","description":"","frontmatter":{},"headers":[],"relativePath":"contributor-guide/compiler-guide.md","filePath":"contributor-guide/compiler-guide.md","lastUpdated":1777400009000}'),r={name:"contributor-guide/compiler-guide.md"};function n(l,e,s,d,p,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="compiler-guide" tabindex="-1">Compiler Guide <a class="header-anchor" href="#compiler-guide" aria-label="Permalink to &quot;Compiler Guide&quot;">​</a></h1><p>The goal of this document is to provide a single point of information for developers interested in improving Vala.</p><p>It is hoped that this document will encourage more Vala users to contribute to Vala by finding/fixing bugs, writing documentation, writing test-cases, and implementing new features.</p><p>In the opinion of this document&#39;s author, a quality Vala 1.0 is an important part of the future of the GNOME Platform, because it will simplify the task of creating and maintaining excellent language-neutral libraries, which are necessary for the next generation of applications.</p><p>The Vala code is fresh, and easy to read. The variable and class names are descriptive, and one often has a general feel of what the code is supposed to do, so the sparse comments are generally not a problem. However, because it is a compiler, Vala is inevitably long, and its call stack deep. This document should provide a high-level view of how Vala is put together.</p><p>This document has been ported from docbook to this wiki in order to be team-maintained and more up-to-date with latest releases of the Vala compiler.</p><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>The complete text of the GNU Free Documentation License can be found here: <a href="http://www.gnu.org/licenses/fdl.html" target="_blank" rel="noreferrer">http://www.gnu.org/licenses/fdl.html</a>.</p><h2 id="acknowledgements" tabindex="-1">Acknowledgements <a class="header-anchor" href="#acknowledgements" aria-label="Permalink to &quot;Acknowledgements&quot;">​</a></h2><p>This document was originally created in 2008 and updated in 2010. Acknowledgements to the original authors:</p><p><strong>Rodney Lorrimar</strong></p><p>Document Author</p><p><strong>Jürg Billeter</strong></p><p>Vala Author</p><p><strong>Raffaele Sandrini</strong></p><p>Vala Author</p><p><strong>Philip van Hoof</strong></p><p>Contribution of the building Vala section.</p><h3 id="edited-by" tabindex="-1">Edited by <a class="header-anchor" href="#edited-by" aria-label="Permalink to &quot;Edited by&quot;">​</a></h3><p>Rodney Lorrimar &lt;<a href="mailto:rodney@rodney.id.au" target="_blank" rel="noreferrer">rodney@rodney.id.au</a>&gt;</p><p>Luca Bruno &lt;<a href="mailto:lethalman88@gmail.com" target="_blank" rel="noreferrer">lethalman88@gmail.com</a>&gt;</p><h2 id="chapters" tabindex="-1">Chapters <a class="header-anchor" href="#chapters" aria-label="Permalink to &quot;Chapters&quot;">​</a></h2><ul class="section-toc"><li><a href="compiler-guide/01-00-project-information">1. Project Information</a></li><li><a href="compiler-guide/02-00-environment-setup">2. Environment Setup</a></li><li><a href="compiler-guide/03-00-the-vala-compiler">3. The Vala Compiler</a></li><li><a href="compiler-guide/04-00-vala-bindings-vapi">4. Vala Bindings - VAPI</a></li><li><a href="compiler-guide/05-00-internal-libgee">5. libgee Internal</a></li><li><a href="compiler-guide/06-00-other-tools">6. Other Tools</a></li><li><a href="compiler-guide/07-00-testing">7. Testing</a></li><li><a href="compiler-guide/08-00-documentation">8. Documentation</a></li><li><a href="compiler-guide/09-00-build-system">9. Build System</a></li></ul>',23)])])}const u=a(r,[["render",n]]);export{m as __pageData,u as default};
